#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=6005;
int n,cnt,dp[405][N];
void dfs()
{
	int id=++cnt;
	int tim,num;
	cin>>tim>>num;
	tim*=2;
	if(num==0)
	{
		int ls=cnt+1;
		dfs();
		int rs=cnt+1;
		dfs();
		for(int i=tim;i<=n-1;i++)
		{
			for(int j=0;j+tim<=i;j++)
			{
				dp[id][i]=max(dp[id][i],dp[ls][j]+dp[rs][i-tim-j]);
			}
		}
	}
	else
	{
		for(int i=tim;i<=n-1;i++)
		{
			dp[id][i]=min(num,(i-tim)/5);
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	dfs();
	cout<<dp[1][n-1];
	return 0;
}
